        // 创建会话表
        const char *createSessionTableSQL = "CREATE TABLE IF NOT EXISTS sessions ("
                                            "id TEXT PRIMARY KEY,"
                                            "agent_name TEXT NOT NULL,"
                                            "created_at DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "latest_message TEXT);";

        // 创建消息表
        const char *createMessageTableSQL = "CREATE TABLE IF NOT EXISTS messages ("
                                            "id TEXT PRIMARY KEY,"
                                            "session_id TEXT NOT NULL,"
                                            "content TEXT NOT NULL,"
                                            "is_sender BOOLEAN NOT NULL,"
                                            "timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,"
                                            "done BOOLEAN DEFAULT 0,"
                                            "context TEXT,"
                                            "FOREIGN KEY(session_id) REFERENCES sessions(id) ON DELETE CASCADE);";

        char *errorMsg;
        if (sqlite3_exec(_chatDatabase, createSessionTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create sessions table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        if (sqlite3_exec(_chatDatabase, createMessageTableSQL, NULL, NULL, &errorMsg) != SQLITE_OK) {
            NSLog(@"Failed to create messages table: %s", errorMsg);
            sqlite3_free(errorMsg);
        }

        // 启用外键支持
        sqlite3_exec(_chatDatabase, "PRAGMA foreign_keys = ON;", NULL, NULL, NULL);
    });
}

