+ (void)ensureResTmpPathReadyForVapp:(WBVAppModel *)vapp completion:(void (^)(NSString *dest, NSError * _Nullable error))completion {
    NSString *dest = [WBStorageManager.sharedManager getUnzipResTmpPath:vapp];
    BOOL isDir = NO;
    BOOL exists = [NSFileManager.defaultManager fileExistsAtPath:dest isDirectory:&isDir];
    if (exists && isDir) {
        if (completion) completion(dest, nil);
        return;
    }
    NSString *zipPath = [WBStorageManager.sharedManager getResCachePath:vapp];
    if (![NSFileManager.defaultManager fileExistsAtPath:zipPath]) {
        if (completion) completion(dest, [NSError errorWithDomain:NSCocoaErrorDomain code:4 userInfo:@{NSLocalizedDescriptionKey: @"res zip missing"}]);
        return;
    }
    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
        [NSFileManager.defaultManager removeItemAtPath:dest error:nil];
        BOOL ok = [SSZipArchive unzipFileAtPath:zipPath toDestination:dest];
        dispatch_async(dispatch_get_main_queue(), ^{
            if (!ok) {
                if (completion) completion(dest, [NSError errorWithDomain:NSCocoaErrorDomain code:5 userInfo:@{NSLocalizedDescriptionKey: @"res unzip failed"}]);
                return;
            }
            vapp.userInfo.resUnzipPath = dest;
            [WBStorageManager.sharedManager markResUnzipCompletedAtPath:dest];
            if (completion) completion(dest, nil);
            [WBUtility calculateSHA1ForFolder:dest includeSubdirectories:YES completion:^(NSString * _Nonnull sha1, NSError * _Nonnull error) {
