- (BOOL)removeCacheFileOrDirIfExist:(NSString *)itemPath {
    if (itemPath == nil) return false;
    if (![[NSFileManager defaultManager] fileExistsAtPath:itemPath isDirectory:nil]) return false;
    NSError *err = nil;
    BOOL success = [[NSFileManager defaultManager] removeItemAtPath:itemPath error:&err];
    NSParameterAssert(success ^ (err != nil));
    return err == nil;
}

@end

