    }
    // 清空下载任务
    _downloadTask = nil;
}

- (void)URLSession:(NSURLSession *)session task:(NSURLSessionTask *)task didCompleteWithError:(NSError *)error {
    if (self.noCompleteWithError) {
        return;
    }
    if (task != self.downloadTask) {
        return;
    }
    if (!error) {
        NSParameterAssert(_downloadingVApp.status == WBVappStatusResourceDownloaded);
        _downloadTask = nil;
        return;
    }
    CFAbsoluteTime timeCost = CFAbsoluteTimeGetCurrent() - _downloadStartTime;
    if ([error.domain isEqualToString:NSURLErrorDomain]) {
        if (error.code == NSURLErrorNetworkConnectionLost) {
            NSLog(@"Resource download: error, connection lost");
        } else if (error.code == NSURLErrorCancelled) {
            NSLog(@"Resource download: error, manually cancelled");
        }
        NSData *resumeData = error.userInfo[NSURLSessionDownloadTaskResumeData];
        [self handleProcessingResumeData:resumeData];
    } else {
        NSLog(@"Resource download: unexpected error occured..");
        [[WBVAppManager sharedManager] saveStatus:WBVappStatusResourceDownloadError forVApp:_downloadingVApp];
        [[WBVAppManager sharedManager] saveError:WBVappStatusResourceDownloadError
                                     errorDomain:error.domain
                                      errorCode:error.code
                                   errorMessage:error.localizedDescription
                                       forVApp:_downloadingVApp];
        [WBEventManager logVappResDownloadResultEvent:_downloadingVApp result:error.description timeCost:timeCost];
    }
    _downloadTask = nil;
}

